create table dirkspzm32.isi_purch_kopf (
    id                    number(*, 0) not null enable,
    sid                   varchar2(2 char) default '01' not null enable,
    firma_nr              number(6, 0) default 1 not null enable,
    status                varchar2(2 char) default 'N' not null enable,
    login_id              number(*, 0),
    lieferant_id          number(*, 0) not null enable,
    kunde_id              number(*, 0),
    info                  varchar2(2000 char),
    liefer_datum          date,
    erz_datum             date,
    aend_datum            date,
    erz_login_id          number(*, 0),
    aend_login_id         number(*, 0),
    vorg_typ              varchar2(5 char) not null enable,
    lief_contact_id       number(*, 0),
    kunde_contact_id      number(*, 0),
    project_nr            varchar2(17 char),
    text_anhang           varchar2(2000 char),
    rechnungs_nr          varchar2(30 char),
    lieferschein_nr       varchar2(30 char),
    lieferschein_datum    date,
    max_pos_nr            number(*, 0) default 0 not null enable,
    ein_lieferant_erlaubt varchar2(1 char),
    kunden_auftrags_nr    varchar2(30 char),
    freitext_ab           varchar2(2000 char),
    freitext_rechnung     varchar2(2000 char),
    freitext_liefs        varchar2(2000 char),
    pro_forma_rech_nr     varchar2(30 char),
    gruss_text_ab         varchar2(2000 char)
);

alter table dirkspzm32.isi_purch_kopf
    add constraint chk_isi_purch_kopf_status
        check ( status in ( 'N', 'B', 'G', 'F', 'E' ) ) enable;

alter table dirkspzm32.isi_purch_kopf
    add constraint chk_isi_purch_kopf_vorg_typ
        check ( vorg_typ in ( 'BE', 'ANG', 'RE', 'KALK', 'ANFR',
                              'LIEF', 'AUFTR', 'GUTS' ) ) enable;

alter table dirkspzm32.isi_purch_kopf
    add constraint pk_purch_kopf primary key ( id )
        using index enable;

alter table dirkspzm32.isi_purch_kopf add constraint uk_purch_kopf unique ( rechnungs_nr )
    using index enable;

alter table dirkspzm32.isi_purch_kopf add constraint uk_purch_kopf_pf_rech_nr unique ( pro_forma_rech_nr )
    using index enable;


